// core/tree/components/CoreTree.tsx

import React, { useImperativeHandle, useState } from 'react';
import {
  View,
  Text,
  Pressable,
  TextInput,
  ScrollView,
  ActivityIndicator,
  StyleSheet,
} from 'react-native';
import { ChevronDown, ChevronRight, Check, Minus } from 'lucide-react-native';

import type { TreeProps, TreeRef, TreeNode, TreeExpandedEvent } from '../types';
import { useTreeEngine } from '../hooks/useTreeEngine';
import { resolveThemeTokenForNative } from '../../../Factory/helpers/style';

const t = resolveThemeTokenForNative;

/* ------------------------------------------------------------------ */
/* Tree Component                                                       */
/* ------------------------------------------------------------------ */

const CoreTree = <T = any,>(props: TreeProps<T>) => {
  const colors = {
    primary: t('primary'),
    primaryDark: t('blue.600'),
    primaryLight: t('blue.50'),
    text: t('gray.700'),
    textSecondary: t('gray.500'),
    border: t('gray.300'),
    surface: '#ffffff',
    disabled: t('gray.400'),
  };

  // Internal filter state (for built-in filter input & imperative ref.filter())
  const [internalFilterValue, setInternalFilterValue] = useState('');
  useImperativeHandle(props.ref, () => ({
    filter: (value: any) => setInternalFilterValue(String(value ?? '')),
  }));

  // Filter value: controlled (props) > internal (built-in input / imperative)
  const resolvedFilterValue = props.filterValue ?? internalFilterValue;

  // Uncontrolled expansion
  const [internalExpandedKeys, setInternalExpandedKeys] =
    useState<Record<string, boolean>>({});

  const resolvedExpandedKeys =
    props.expandedKeys !== undefined
      ? props.expandedKeys
      : internalExpandedKeys;

  const { state, actions } = useTreeEngine({
    nodes: props.value,
    selectionMode: props.selectionMode,
    selectionKeys: props.selectionKeys,
    metaKeySelection: props.metaKeySelection,
    expandedKeys: props.expandedKeys,
    filterValue: resolvedFilterValue,
    filterBy: props.filterBy,
    filterMode: props.filterMode,
    onSelectionChange: props.onSelectionChange,
    onToggle: props.onToggle,
    onExpand: props.onExpand,
    onCollapse: props.onCollapse,
  });

  const handleToggle = (node: TreeNode, originalEvent?: any) => {
    const key = node.key;
    if (!key) return;

    const nextExpandedKeys = { ...resolvedExpandedKeys };
    if (nextExpandedKeys[key]) {
      delete nextExpandedKeys[key];
    } else {
      nextExpandedKeys[key] = true;
    }

    if (props.expandedKeys === undefined) {
      setInternalExpandedKeys(nextExpandedKeys);
    }

    props.onToggle?.({
      originalEvent,
      value: nextExpandedKeys,
    } as unknown as TreeExpandedEvent<T>);

    if (nextExpandedKeys[key]) {
      props.onExpand?.({ originalEvent, node });
    } else {
      props.onCollapse?.({ originalEvent, node });
    }
  };

  /* ---- Selection helpers ---- */

  const isNodeSelected = (node: TreeNode): boolean => {
    if (!props.selectionMode || !props.selectionKeys) return false;
    if (props.selectionMode === 'single') return props.selectionKeys === node.key;
    if (props.selectionMode === 'multiple') return !!(props.selectionKeys as any)?.[node.key];
    if (props.selectionMode === 'checkbox') return !!(props.selectionKeys as any)?.[node.key]?.checked;
    return false;
  };

  const isNodePartialChecked = (node: TreeNode): boolean => {
    if (props.selectionMode !== 'checkbox' || !props.selectionKeys) return false;
    const entry = (props.selectionKeys as any)?.[node.key];
    return !!entry?.partialChecked && !entry?.checked;
  };

  /* ---- Checkbox ---- */

  const renderCheckbox = (node: TreeNode) => {
    const checked = isNodeSelected(node);
    const partial = isNodePartialChecked(node);

    return (
      <Pressable
        onPress={(e) => {
          if (node.selectable !== false && !node.disabled) {
            actions.selectNode(node.key, { originalEvent: e });
          }
        }}
        style={[
          styles.checkbox,
          { borderColor: colors.border, backgroundColor: '#fff' },
          checked && { backgroundColor: colors.primary, borderColor: colors.primary },
          partial && { backgroundColor: colors.primary, borderColor: colors.primary },
          node.disabled && styles.checkboxDisabled,
        ]}
      >
        {checked && <Check size={12} color="#fff" strokeWidth={3} />}
        {partial && !checked && <Minus size={12} color="#fff" strokeWidth={3} />}
      </Pressable>
    );
  };

  /* ---- Toggler ---- */

  const renderToggler = (node: TreeNode, expanded: boolean) => {
    if (props.togglerTemplate) {
      return props.togglerTemplate(node, { expanded });
    }

    return (
      <Pressable
        onPress={(e) => handleToggle(node, e)}
        hitSlop={6}
        style={styles.toggler}
      >
        {expanded ? (
          <ChevronDown size={16} color={colors.textSecondary} />
        ) : (
          <ChevronRight size={16} color={colors.textSecondary} />
        )}
      </Pressable>
    );
  };

  /* ---- Node rendering ---- */

  const renderNode = (node: TreeNode, level = 0) => {
    // onlyParentsWithChildren: skip nodes that have no children
    if (props.onlyParentsWithChildren && (!node.children || node.children.length === 0)) {
      return null;
    }

    const expanded = !!resolvedExpandedKeys?.[node.key];
    const hasChildren = !!node.children?.length || node.leaf === false;
    const isSelected = isNodeSelected(node);
    const isSelectable = node.selectable !== false && !node.disabled;

    return (
      <View key={node.key} style={{ paddingLeft: level * 20 }} >
        <Pressable
          disabled={node.disabled}
          onPress={(e) => {
            // Node click event
            props.onNodeClick?.({
              originalEvent: e as any,
              node: node as any,
            });

            // Selection (non-checkbox — checkbox uses its own pressable)
            if (props.selectionMode && props.selectionMode !== 'checkbox' && isSelectable) {
              actions.selectNode(node.key, { originalEvent: e });
            }
          }}
          style={[
            styles.nodeContent,
            isSelected && { backgroundColor: colors.primaryLight },
            node.disabled && styles.nodeContentDisabled,
          ]}
        >
          {/* Toggler - comes first like PrimeReact */}
          {hasChildren ? (
            renderToggler(node, expanded)
          ) : (
            <View style={styles.togglerPlaceholder} />
          )}

          {/* Checkbox */}
          {props.selectionMode === 'checkbox' && (
            <View style={styles.checkboxWrapper}>
              {renderCheckbox(node)}
            </View>
          )}

          {/* Node content */}
          <View style={styles.nodeLabel}>
            {props.nodeTemplate ? (
              props.nodeTemplate(node, { expanded, level, selected: isSelected })
            ) : (
              <Text
                style={[
                  styles.nodeLabelText,
                  { color: colors.text },
                  isSelected && { color: colors.primaryDark, fontWeight: '600' as const },
                  node.disabled && { color: colors.disabled },
                ]}
                numberOfLines={1}
              >
                {node.label}
              </Text>
            )}
          </View>
        </Pressable>

        {/* Children - rendered inside the indented container */}
        {expanded && node.children?.map((child) => renderNode(child, level + 1))}
      </View>
    );
  };

  /* ---- Loading ---- */

  if (props.loading) {
    return (
      <View style={[styles.container, { backgroundColor: colors.surface, borderColor: colors.border }, props.style]}>
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="small" color={colors.primary} />
        </View>
      </View>
    );
  }

  /* ---- Main render ---- */

  return (
    <View style={[styles.container, { backgroundColor: colors.surface, borderColor: colors.border }, props.style]}>
      {/* Filter input */}
      {props.filter && (
        <View style={[styles.filterContainer, { borderBottomColor: colors.border }]}>
          <TextInput
            value={resolvedFilterValue}
            onChangeText={(text) => {
              setInternalFilterValue(text);
            }}
            placeholder={props.filterPlaceholder ?? 'Search'}
            placeholderTextColor={colors.textSecondary}
            style={[styles.filterInput, {
              borderColor: colors.border,
              color: colors.text,
              backgroundColor: colors.surface,
            }]}
          />
        </View>
      )}

      {/* Tree nodes */}
      <ScrollView style={styles.scrollContainer}>
        {state.nodes?.map((node) => renderNode(node))}

        {(!state.nodes || state.nodes.length === 0) && (
          <View style={styles.emptyContainer}>
            <Text style={[styles.emptyText, { color: colors.textSecondary }]}>{props.emptyMessage ?? 'No records found'}</Text>
          </View>
        )}
      </ScrollView>
    </View>
  );
};

/* ------------------------------------------------------------------ */
/* Styles (layout only — colors applied inline via theme tokens)       */
/* ------------------------------------------------------------------ */

const styles = StyleSheet.create({
  container: {
    borderWidth: 1,
    borderRadius: 6,
    overflow: 'hidden',
  },
  scrollContainer: {
    padding: 4,
  },

  // Filter
  filterContainer: {
    padding: 8,
    borderBottomWidth: 1,
  },
  filterInput: {
    height: 36,
    borderWidth: 1,
    borderRadius: 6,
    paddingHorizontal: 10,
    fontSize: 14,
  },

  // Node
  nodeContent: {
    flexDirection: 'row',
    alignItems: 'center',
    minHeight: 38,
    paddingVertical: 4,
    paddingHorizontal: 4,
    borderRadius: 4,
  },
  nodeContentDisabled: {
    opacity: 0.5,
  },

  // Toggler
  toggler: {
    width: 28,
    height: 28,
    borderRadius: 14,
    justifyContent: 'center',
    alignItems: 'center',
  },
  togglerPlaceholder: {
    width: 28,
  },

  // Checkbox
  checkboxWrapper: {
    marginRight: 4,
  },
  checkbox: {
    width: 20,
    height: 20,
    borderWidth: 2,
    borderRadius: 4,
    justifyContent: 'center',
    alignItems: 'center',
  },
  checkboxDisabled: {
    opacity: 0.5,
  },

  // Label
  nodeLabel: {
    flex: 1,
    paddingLeft: 4,
  },
  nodeLabelText: {
    fontSize: 14,
  },

  // Loading
  loadingContainer: {
    padding: 24,
    alignItems: 'center',
  },

  // Empty
  emptyContainer: {
    padding: 16,
    alignItems: 'center',
  },
  emptyText: {
    fontSize: 14,
  },
});

export default CoreTree;
